# ❌ ANTI-PATTERN: Allocating memory inside hot kernels
class PoorBattingAverageLoss(torch.autograd.Function):
    @staticmethod
    def forward(ctx, batting_scores):
        # Allocates new buffers every forward pass—wasteful!
        device = batting_scores.device
        temp_buffer = torch.zeros(batting_scores.shape, device=device)
        intermediate = torch.zeros(batting_scores.shape, device=device)
        # ... computation ...
        return temp_buffer  # Leaks memory, no backward defined

# ✅ BEST PRACTICE: Pre-allocate and reuse buffers (Memory-First)
class OptimizedBattingAverageLoss(torch.autograd.Function):
    def __init__(self, batch_size, feature_dim, device):
        self.temp_buffer = torch.zeros(batch_size, feature_dim, device=device)
        self.intermediate = torch.zeros(batch_size, feature_dim, device=device)

    @staticmethod
    def forward(ctx, batting_scores, buffer_pool):
        # Reuse pre-allocated buffers
        temp = buffer_pool['temp']
        temp.zero_()
        torch.mm(batting_scores, batting_scores.T, out=temp)
        ctx.save_for_backward(batting_scores, temp)
        return temp.clone()

    @staticmethod
    def backward(ctx, grad_output):
        batting_scores, temp = ctx.saved_tensors
        grad_scores = torch.mm(grad_output, batting_scores)
        return grad_scores, None

# ✅ BEST PRACTICE: Latency-First with kernel fusion
class FusedBowlingStrategyKernel(torch.autograd.Function):
    @staticmethod
    def forward(ctx, pace_delivery, spin_delivery, match_context):
        # Single fused kernel handles normalization + activation + scaling
        output = torch.ops.custom_ops.fused_bowling_kernel(
            pace_delivery, spin_delivery, match_context
        )
        ctx.save_for_backward(pace_delivery, spin_delivery)
        return output

# ✅ BEST PRACTICE: Gradient-Safe with checkpointing
def safe_cricket_simulation(wicket_state, bowler_stats, runs_required):
    # Checkpoint at decision points
    def phase1(x):
        return torch.nn.functional.relu(x @ bowler_stats)

    def phase2(x):
        return torch.sigmoid(x + runs_required)

    # Only store wicket_state, recompute phase1 during backward
    x = checkpoint(phase1, wicket_state)
    output = checkpoint(phase2, x)
    return output

# Real-world example: Fused batsman_scoring operation
# Combines normalization + activation + scaling (like Flash Attention pattern)

import torch
import torch.cuda
from torch.utils.cpp_extension import load_inline

cuda_source = """
__global__ void fused_batsman_score_kernel(
    float* runs, float* strike_rate, float* boundaries,
    float* output, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < N) {
        float normalized = (runs[idx] - 50.0f) / 20.0f;  // Normalize
        float activated = max(0.0f, normalized);          // ReLU
        output[idx] = activated * strike_rate[idx] * boundaries[idx];
    }
}

torch::Tensor fused_batsman_score(
    torch::Tensor runs,
    torch::Tensor strike_rate,
    torch::Tensor boundaries) {
    auto output = torch::empty_like(runs);
    int N = runs.numel();
    int threads = 256;
    int blocks = (N + threads - 1) / threads;
    fused_batsman_score_kernel<<<blocks, threads>>>(
        runs.data_ptr<float>(),
        strike_rate.data_ptr<float>(),
        boundaries.data_ptr<float>(),
        output.data_ptr<float>(), N);
    return output;
}
"""

# Usage in production
batsman_runs = torch.randn(1000000, device='cuda')
strike_rates = torch.randn(1000000, device='cuda')
boundaries = torch.randn(1000000, device='cuda')

# Fused kernel processes all operations in single GPU pass
scores = fused_batsman_score(batsman_runs, strike_rates, boundaries)
print(f'Processed {scores.numel()} batsmen scores in one kernel launch')
